def _calc_adj(trend, vr, dif, macd_val, rsi_val, cur, ma20, ma60, lb):
    """
    计算综合调整系数（不含板位因子，板位由 lb_risk 单独处理）
    """
    adj = 1.0
    if trend == "上升通道":
        adj *= 1.25
    elif trend == "下降通道":
        adj *= 0.70
    else:  # 震荡
        adj *= 0.95

    if vr is not None:
        if vr > 2.0:
            adj *= 1.30
        elif vr > 1.5:
            adj *= 1.15
        elif vr < 0.5:
            adj *= 0.80
        elif vr < 0.8:
            adj *= 0.90

    if rsi_val is not None:
        if rsi_val > 80:
            adj *= 0.70
        elif rsi_val > 75:
            adj *= 0.80
        elif rsi_val < 30:
            adj *= 0.80
        elif rsi_val < 40:
            adj *= 0.90

    # macd_val 即 DIF-DE 值（MACD柱状图）
    if macd_val is not None:
        if macd_val > 0:
            adj *= 1.10
        else:
            adj *= 0.90

    # 板位因子已移至 lb_risk，避免双重折扣
    return round(adj, 2)


